import org.apache.flink.streaming.api.windowing.assigners.EventTimeSessionWindows;
import org.apache.flink.streaming.api.windowing.time.Time;
import org.apache.flink.util.Collector;

import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.PrintWriter;
import java.time.Duration;

public class LongestSessionPerJob extends AppBase {

    public static void main(String[] args) throws Exception {

        ParameterTool params = ParameterTool.fromArgs(args);
        String taskInput = params.get("task_input", null);
        String jobInput = params.get("job_input", null);
        String outputPath = params.get("output", null);
        System.out.println("task_input  " + taskInput);
        System.out.println("job_input  " + jobInput);
        final int sesssize = params.getInt("sesssize", 600);

        // 10 minutes in milliseconds for Flink event time (timestamps are microseconds, we divide by 1000)
        final long SESSION_GAP_MS = 10L * 60L * 1000L;

        StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();
        env.setParallelism(1);

        // Task events source
        SourceFunction<TaskEvent> taskSource = AppBase.taskSourceOrTest(
            new GzipCsvSource<>(taskInput, TaskEvent::fromCsvLine)
        );

        // Job events source
        SourceFunction<JobEvent> jobSource = AppBase.jobSourceOrTest(
            new GzipCsvSource<>(jobInput, JobEvent::fromCsvLine)
        );

        // Task stream with event-time watermarks (convert microseconds -> milliseconds)
        DataStream<TaskEvent> taskStream = env
            .addSource(taskSource)
            .assignTimestampsAndWatermarks(
                WatermarkStrategy.<TaskEvent>forBoundedOutOfOrderness(Duration.ofSeconds(0))
                    .withTimestampAssigner((event, ts) -> event.timestamp / 1000L)
            );

        // Job stream with event-time watermarks
        DataStream<JobEvent> jobStream = env
            .addSource(jobSource)
            .assignTimestampsAndWatermarks(
                WatermarkStrategy.<JobEvent>forBoundedOutOfOrderness(Duration.ofSeconds(0))
                    .withTimestampAssigner((event, ts) -> event.timestamp / 1000L)
            );

        // Filter only SUBMIT task events
        DataStream<TaskEvent> submitEvents = taskStream
            .filter(e -> e.eventType == TaskEvent.SUBMIT);

        // Session windowing: group SUBMIT events per job into stages (gap = 10 min)
        // Each window = one stage; count tasks in that stage
        DataStream<Tuple2<Long, Long>> stageCounts = submitEvents
            .keyBy(e -> e.jobId)
            .window(EventTimeSessionWindows.withGap(Time.milliseconds(SESSION_GAP_MS)))
            .aggregate(new CountTasksInStage());

        // For each job, keep running max of stage task count
        DataStream<Tuple2<Long, Long>> maxPerJob = stageCounts
            .keyBy(t -> t.f0)
            .reduce((ReduceFunction<Tuple2<Long, Long>>) (a, b) ->
                new Tuple2<>(a.f0, Math.max(a.f1, b.f1)));

        // Finished job IDs
        DataStream<Long> finishedJobs = jobStream
            .filter(e -> e.eventType == JobEvent.FINISH)
            .map(e -> e.jobId);

        // Join: only emit result when job has a FINISH event
        DataStream<Tuple2<Long, Long>> result = maxPerJob
            .keyBy(t -> t.f0)
            .connect(finishedJobs.keyBy(id -> id))
            .process(new WaitForFinishFunction());

        // Sink
        SinkFunction<Tuple2<Long, Long>> sink;
        if (outputPath != null) {
            sink = (SinkFunction<Tuple2<Long, Long>>) AppBase.sinkOrTest(new FileSink<>(outputPath));
        } else {
            sink = (SinkFunction<Tuple2<Long, Long>>) AppBase.sinkOrTest(new PrintSinkFunction<>());
        }
        result.addSink(sink);

        env.execute("LongestSessionPerJob");
    }

    /** Counts task SUBMIT events in a session window, producing (jobId, count). */
    public static class CountTasksInStage
            implements AggregateFunction<TaskEvent, Tuple2<Long, Long>, Tuple2<Long, Long>> {

        @Override
        public Tuple2<Long, Long> createAccumulator() {
            return new Tuple2<>(-1L, 0L);
        }

        @Override
        public Tuple2<Long, Long> add(TaskEvent event, Tuple2<Long, Long> acc) {
            return new Tuple2<>(event.jobId, acc.f1 + 1L);
        }

        @Override
        public Tuple2<Long, Long> getResult(Tuple2<Long, Long> acc) {
            return acc;
        }

        @Override
        public Tuple2<Long, Long> merge(Tuple2<Long, Long> a, Tuple2<Long, Long> b) {
            return new Tuple2<>(a.f0, a.f1 + b.f1);
        }
    }

    /**
     * Buffers the max stage count per job; emits result when a FINISH event arrives.
     * Stream 1: (jobId, maxStageCount) updates
     * Stream 2: finished jobId signals
     */
    public static class WaitForFinishFunction
            extends KeyedCoProcessFunction<Long, Tuple2<Long, Long>, Long, Tuple2<Long, Long>> {

        private ValueState<Long> maxStageCount;
        private ValueState<Boolean> emitted;

        @Override
        public void open(Configuration parameters) {
            maxStageCount = getRuntimeContext().getState(
                new ValueStateDescriptor<>("maxStageCount", Long.class));
            emitted = getRuntimeContext().getState(
                new ValueStateDescriptor<>("emitted", Boolean.class));
        }

        @Override
        public void processElement1(Tuple2<Long, Long> value, Context ctx,
                Collector<Tuple2<Long, Long>> out) throws Exception {
            Long current = maxStageCount.value();
            if (current == null || value.f1 > current) {
                maxStageCount.update(value.f1);
            }
        }

        @Override
        public void processElement2(Long jobId, Context ctx,
                Collector<Tuple2<Long, Long>> out) throws Exception {
            Boolean alreadyEmitted = emitted.value();
            if (alreadyEmitted != null && alreadyEmitted) return;
            Long count = maxStageCount.value();
            if (count != null) {
                out.collect(new Tuple2<>(jobId, count));
                emitted.update(true);
            }
        }
    }

    /** Writes one tuple per line to a local file. */
    public static class FileSink<T> implements SinkFunction<T> {
        private final String path;
        private transient PrintWriter writer;

        public FileSink(String path) {
            this.path = path;
        }

        @Override
        public void invoke(T value, Context context) throws Exception {
            if (writer == null) {
                writer = new PrintWriter(new BufferedWriter(new FileWriter(path, true)));
            }
            writer.println(value.toString());
            writer.flush();
        }
    }
}

