import java.util.zip.GZIPInputStream;

public class LongestSessionPerJob extends AppBase {

    private static final long SESSION_GAP_MICROS = 10L * 60L * 1_000_000L;

    public static void main(String[] args) throws Exception {

        ParameterTool params = ParameterTool.fromArgs(args);
        final String taskInput = params.get("task_input", null);
        final String jobInput = params.get("job_input", null);
        final String outputPath = params.get("output", null);

        System.out.println("task_input  " + taskInput);
        System.out.println("job_input  " + jobInput);

        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();
        env.setParallelism(1);

        @SuppressWarnings("unchecked")
        SinkFunction<Tuple2<Long, Integer>> sink = (SinkFunction<Tuple2<Long, Integer>>) AppBase.sinkOrTest(
                new FileSink(outputPath));

        if (AppBase.taskEvents != null || AppBase.jobEvents != null) {
            // Test mode: use injected sources with KeyedCoProcessFunction
            DataStream<TaskEvent> taskSubmits = env.addSource(
                    AppBase.taskSourceOrTest(new NoOpTaskSource()),
                    Types.POJO(TaskEvent.class));

            DataStream<JobEvent> jobFinishes = env.addSource(
                    AppBase.jobSourceOrTest(new NoOpJobSource()),
                    Types.POJO(JobEvent.class));

            DataStream<Tuple2<Long, Integer>> results = taskSubmits
                    .keyBy(e -> e.jobId)
                    .connect(jobFinishes.keyBy(e -> e.jobId))
                    .process(new LongestStageFunction());

            results.addSink(sink);
        } else {
            // File mode: read both files in a single source to guarantee ordering
            DataStream<Tuple2<Long, Integer>> results = env.addSource(
                    new BothFilesSource(taskInput, jobInput),
                    Types.TUPLE(Types.LONG, Types.INT));
            results.addSink(sink);
        }

        env.execute("LongestSessionPerJob");
    }

    // ---- Single source that reads both files (task first, then job) ----

    public static class BothFilesSource implements SourceFunction<Tuple2<Long, Integer>> {
        private final String taskPath;
        private final String jobPath;

        public BothFilesSource(String taskPath, String jobPath) {
            this.taskPath = taskPath;
            this.jobPath = jobPath;
        }

        @Override
        public void run(SourceContext<Tuple2<Long, Integer>> ctx) throws Exception {
            // Step 1: collect all SUBMIT timestamps per job
            Map<Long, List<Long>> submitsByJob = new HashMap<>();
            if (taskPath != null) {
                try (BufferedReader reader = new BufferedReader(
                        new InputStreamReader(new GZIPInputStream(new FileInputStream(taskPath))))) {
                    String line;
                    while ((line = reader.readLine()) != null) {
                        TaskEvent e = TaskEvent.fromString(line);
                        if (e != null && e.eventType == 0) {
                            submitsByJob.computeIfAbsent(e.jobId, k -> new ArrayList<>()).add(e.timestamp);
                        }
                    }
                }
            }

            // Step 2: collect finished job IDs
            Set<Long> finishedJobs = new HashSet<>();
            if (jobPath != null) {
                try (BufferedReader reader = new BufferedReader(
                        new InputStreamReader(new GZIPInputStream(new FileInputStream(jobPath))))) {
                    String line;
                    while ((line = reader.readLine()) != null) {
                        JobEvent e = JobEvent.fromString(line);
                        if (e != null && e.eventType == 4) {
                            finishedJobs.add(e.jobId);
                        }
                    }
                }
            }

            // Step 3: compute longest session for each finished job
            for (long jobId : finishedJobs) {
                List<Long> timestamps = submitsByJob.get(jobId);
                if (timestamps == null || timestamps.isEmpty()) continue;

                Collections.sort(timestamps);

                int maxStageCount = 0;
                int currentCount = 1;

                for (int i = 1; i < timestamps.size(); i++) {
                    long gap = timestamps.get(i) - timestamps.get(i - 1);
                    if (gap <= SESSION_GAP_MICROS) {
                        currentCount++;
                    } else {
                        if (currentCount > maxStageCount) {
                            maxStageCount = currentCount;
                        }
                        currentCount = 1;
                    }
                }
                if (currentCount > maxStageCount) {
                    maxStageCount = currentCount;
                }

                ctx.collect(Tuple2.of(jobId, maxStageCount));
            }
        }

        @Override
        public void cancel() {}
    }

    // ---- No-op sources (used in test mode when AppBase injects real sources) ----

    public static class NoOpTaskSource implements SourceFunction<TaskEvent> {
        @Override public void run(SourceContext<TaskEvent> ctx) {}
        @Override public void cancel() {}
    }

    public static class NoOpJobSource implements SourceFunction<JobEvent> {
        @Override public void run(SourceContext<JobEvent> ctx) {}
        @Override public void cancel() {}
    }

    // ---- Process Function (used in test mode) ----

    public static class LongestStageFunction
            extends KeyedCoProcessFunction<Long, TaskEvent, JobEvent, Tuple2<Long, Integer>> {

        private ListState<Long> submitTimestamps;
        private ValueState<Boolean> finished;

        @Override
        public void open(Configuration cfg) throws Exception {
            submitTimestamps = getRuntimeContext().getListState(
                    new ListStateDescriptor<>("submits", Types.LONG));
            finished = getRuntimeContext().getState(
                    new ValueStateDescriptor<>("finished", Types.BOOLEAN));
        }

        @Override
        public void processElement1(TaskEvent event, Context ctx, Collector<Tuple2<Long, Integer>> out)
                throws Exception {
            Boolean done = finished.value();
            if (done == null || !done) {
                submitTimestamps.add(event.timestamp);
            }
        }

        @Override
        public void processElement2(JobEvent event, Context ctx, Collector<Tuple2<Long, Integer>> out)
                throws Exception {
            Boolean done = finished.value();
            if (done != null && done) return;
            finished.update(true);

            List<Long> timestamps = new ArrayList<>();
            for (Long ts : submitTimestamps.get()) {
                timestamps.add(ts);
            }

            if (timestamps.isEmpty()) return;

            Collections.sort(timestamps);

            int maxStageCount = 0;
            int currentCount = 1;

            for (int i = 1; i < timestamps.size(); i++) {
                long gap = timestamps.get(i) - timestamps.get(i - 1);
                if (gap <= SESSION_GAP_MICROS) {
                    currentCount++;
                } else {
                    if (currentCount > maxStageCount) {
                        maxStageCount = currentCount;
                    }
                    currentCount = 1;
                }
            }
            if (currentCount > maxStageCount) {
                maxStageCount = currentCount;
            }

            out.collect(Tuple2.of(event.jobId, maxStageCount));
        }
    }

    // ---- Sink ----

    public static class FileSink implements SinkFunction<Tuple2<Long, Integer>> {
        private final String path;
        private transient PrintWriter writer;

        public FileSink(String path) {
            this.path = path;
        }

        @Override
        public void invoke(Tuple2<Long, Integer> value, Context context) throws Exception {
            if (writer == null) {
                writer = new PrintWriter(new BufferedWriter(new FileWriter(path, true)));
            }
            writer.println("(" + value.f0 + "," + value.f1 + ")");
            writer.flush();
        }
    }
}

